<?php require_once __DIR__.'/../../backend/shared/auth.php'; require_role('patient'); require_once __DIR__.'/../../backend/shared/layout.php';
$pid=$_SESSION['user']['id']; $p=db()->prepare('SELECT * FROM patients WHERE id=?');$p->execute([$pid]);$p=$p->fetch();
$v=db()->prepare('SELECT * FROM visits WHERE patient_id=? ORDER BY visit_date DESC,id DESC LIMIT 3');$v->execute([$pid]);$visits=$v->fetchAll(); $count=db()->prepare('SELECT COUNT(*) FROM visits WHERE patient_id=?');$count->execute([$pid]);$count=$count->fetchColumn();
$a=db()->prepare('SELECT * FROM appointments WHERE patient_id=? AND appointment_date>=CURDATE() ORDER BY appointment_date ASC LIMIT 3');$a->execute([$pid]);$appts=$a->fetchAll(); $r=db()->prepare('SELECT * FROM ai_risk_assessments WHERE patient_id=? ORDER BY id DESC LIMIT 1');$r->execute([$pid]);$risk=$r->fetch();
app_header('ข้อมูลสุขภาพของฉัน','patient','portal'); ?>
<div class="grid two"><div class="card"><h3><?=e($p['first_name'].' '.$p['last_name'])?></h3><p class="tl-meta">HN <?=e($p['hn'])?> · <?=e($p['sex'])?> · อายุ <?=e($p['age'])?> · BMI <?=e($p['bmi'])?></p><p><b>แพ้ยา:</b> <?=e($p['allergy'])?></p><a class="btn secondary" href="<?=APP_URL?>/support.php">แจ้งปัญหาข้อมูล</a></div><div class="card riskbox"><h3>ผลประเมิน AI ล่าสุด</h3><?php if($risk):?><div class="tl-head"><span class="badge <?=$risk['level']==='High'?'red':($risk['level']==='Moderate'?'warn':'')?>"><?=e($risk['level'])?></span><b><?=$risk['score']?>/100</b></div><div class="riskbar"><span style="width:<?=$risk['score']?>%"></span></div><p><?=e($risk['recommendation'])?></p><?php else:?><p>ยังไม่มีผลประเมิน</p><?php endif;?></div></div>
<div class="card" style="margin-top:18px"><h3>แจ้งเตือนนัดติดตาม</h3><?php if(!$appts):?><p class="tl-meta">ยังไม่มีนัดติดตาม</p><?php endif;?><?php foreach($appts as $ap):?><div class="notice" style="margin-bottom:8px">📅 <?=e($ap['appointment_date'])?> · <?=e($ap['department'])?> · แพทย์ <?=e($ap['doctor_name'])?> · <?=e($ap['reason'])?></div><?php endforeach;?></div>
<div class="card" style="margin-top:18px"><div class="tl-head"><h3>Timeline การรับบริการ</h3><span class="badge gray">แสดง 3 จาก <?=$count?></span></div><div class="timeline"><?php foreach($visits as $vv):?><div class="tl-item"><div class="tl-head"><div><div class="tl-title"><?=e($vv['visit_date'])?> · <?=e($vv['hospital_name'])?></div><div class="tl-meta"><?=e($vv['department'])?> · <?=e($vv['visit_type'])?> · แพทย์ <?=e($vv['doctor_name'])?></div></div><a class="btn secondary" href="visit-detail.php?id=<?=$vv['id']?>">ดูรายละเอียด</a></div><p><b>เข้ารพ.เพราะ:</b> <?=e($vv['chief_complaint'])?></p></div><?php endforeach;?></div><?php if($count>3):?><a class="btn secondary" href="timeline.php">ดู Timeline เพิ่มเติม</a><?php endif;?></div><?php app_footer();?>
